  ('real-estate-moex-02145', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於普通抵押權之敘述，下列何者錯誤？', '["抵押權之設定須以書面為之，並辦理登記", "抵押人設定抵押權時，對於抵押物須有所有權及處分權", "以抵押權所擔保之債權，經讓與其一部者，抵押權仍不受影響", "於抵押權所擔保之債權全部被清償時，抵押權仍不消滅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02146', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列關於地上權之敘述，何者正確？', '["稱普通地上權者，謂以在他人土地之上下有建築物或種植竹木為目的而使用其土地之權", "地上權不因建築物或其他工作物之滅失而消滅", "地上權人均得隨時拋棄其權利", "土地所有權讓與時，已預付之地租，均不得對抗第三人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02147', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲有A、B二地，因出賣A地給乙，致B地與公路無適宜之連絡，不能為通常之使用。下列敘述何者正 確？', '["甲可以任擇A地或其他相鄰之地而通行之", "甲通行鄰地已造成鄰地負擔，不得再主張開設道路", "甲通行鄰地時，為求便利，可任意選擇通行之處所", "若甲不主張開設道路而通行A地，無須支付乙償金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02148', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲死亡，遺留房屋一棟，有乙、丙二位繼承人。下列敘述何者正確？', '["未分割前，該屋為乙、丙分別共有", "移轉登記前，乙、丙即取得該屋所有權，然而應經登記，始得處分之", "若該屋被無權占有，乙、丙須共同向無權占有人起訴請求返還", "若乙、丙於繼承前於該屋上有抵押權，該抵押權不因繼承而受影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02149', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列關於動產之敘述，何者錯誤？', '["甲以占有之意思，占有被遺棄之流浪狗，甲取得該狗之所有權", "公園管理員在所管理之公園內拾得遺失物者，對遺失人不得請求報酬", "甲乙各有一桶白油漆，不慎混合在一起，二人應按其混合時之價值，共有混合後之油漆", "加工於他人之動產者，其加工物之所有權，原則上屬於加工人"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 27, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02150', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將其所有之A車借給乙，不久卻將A車贈與給乙，則甲對乙得以何種方式交付A車？', '["現實交付", "簡易交付", "占有改定", "指示交付"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02151', 'real-estate', 'real-estate-moex-100-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將A屋設定普通抵押權給乙銀行後，甲又將該A屋出租給丙，下列敘述何者為正確？', '["甲乙間之抵押權無效", "甲丙間之租約無效", "甲乙間之抵押權不因此而受影響，但A屋之租金由乙收取之", "甲乙間之抵押權不因此而受影響，A屋之租金仍由甲收取之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:11+00:00", "source_pdf_sha1": "a93c69d8c61a", "answer_pdf_sha1": "2e4520275a22", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "601", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
